import { createHash } from "node:crypto";
import type { Chunk } from "./types";
import type { IngestedFile } from "./ingest";

const CHUNK_LINES = 60;
const OVERLAP_LINES = 10;
export const MAX_CHUNKS = 3000;

/** Split a single file into overlapping line windows. */
export function chunkFile(file: IngestedFile): Chunk[] {
  const lines = file.content.split("\n");
  const chunks: Chunk[] = [];
  const step = Math.max(1, CHUNK_LINES - OVERLAP_LINES);

  for (let start = 0; start < lines.length; start += step) {
    const end = Math.min(start + CHUNK_LINES, lines.length);
    const text = lines.slice(start, end).join("\n").trim();
    if (text.length === 0) {
      if (end >= lines.length) break;
      continue;
    }
    const id = createHash("sha1")
      .update(`${file.relPath}:${start}`)
      .digest("hex")
      .slice(0, 16);
    chunks.push({
      id,
      file: file.relPath,
      startLine: start + 1,
      endLine: end,
      text,
    });
    if (end >= lines.length) break;
  }

  return chunks;
}

/** Chunk every file, capped so indexing stays fast for a hackathon demo. */
export function chunkFiles(files: IngestedFile[]): Chunk[] {
  const all: Chunk[] = [];
  for (const file of files) {
    for (const chunk of chunkFile(file)) {
      all.push(chunk);
      if (all.length >= MAX_CHUNKS) return all;
    }
  }
  return all;
}

import { pipeline, type FeatureExtractionPipeline } from "@huggingface/transformers";

const MODEL = "Xenova/all-MiniLM-L6-v2";
export const EMBEDDING_DIM = 384;
const BATCH_SIZE = 32;

let extractorPromise: Promise<FeatureExtractionPipeline> | null = null;

/**
 * Lazily load the embedding model once per process. The model (~90MB) is
 * downloaded and cached on first use; no API key is required.
 */
function getExtractor(): Promise<FeatureExtractionPipeline> {
  if (!extractorPromise) {
    extractorPromise = pipeline("feature-extraction", MODEL);
  }
  return extractorPromise;
}

/** Embed a batch of texts into L2-normalized 384-dim vectors. */
export async function embed(texts: string[]): Promise<number[][]> {
  if (texts.length === 0) return [];
  const extractor = await getExtractor();
  const vectors: number[][] = [];

  for (let i = 0; i < texts.length; i += BATCH_SIZE) {
    const batch = texts.slice(i, i + BATCH_SIZE);
    const output = await extractor(batch, { pooling: "mean", normalize: true });
    vectors.push(...(output.tolist() as number[][]));
  }

  return vectors;
}

export async function embedOne(text: string): Promise<number[]> {
  const [vector] = await embed([text]);
  return vector;
}

