/** Return the top-k most similar chunks for a query vector. */
export async function search(
  id: string,
  queryVector: number[],
  k = 6,
): Promise<RetrievedChunk[]> {
  const rec = await getIndex(id);
  if (!rec) throw new Error(`Index not found: ${id}`);

  const scored = rec.chunks.map((chunk, i) => ({
    chunk,
    score: cosine(queryVector, rec.vectors[i]),
  }));

  scored.sort((a, b) => b.score - a.score);

  return scored.slice(0, k).map(({ chunk, score }) => ({
    file: chunk.file,
    startLine: chunk.startLine,
    endLine: chunk.endLine,
    text: chunk.text,
    score,
  }));
}

export interface Chunk {
  id: string;
  file: string;
  startLine: number;
  endLine: number;
  text: string;
}

export interface IndexRecord {
  id: string;
  source: string;
  createdAt: number;
  fileCount: number;
  chunks: Chunk[];
  vectors: number[][];
}

/** Lightweight view returned to the client (no vectors / chunk text). */
export interface IndexSummary {
  id: string;
  source: string;
  createdAt: number;
  fileCount: number;
  chunkCount: number;
}

export interface RetrievedChunk {
  file: string;
  startLine: number;
  endLine: number;
  text: string;
  score: number;
}
